# Could not find any slot — build a comprehensive reason message
if blocker_set:
    # Priority: attendee_unavailable > daily_limit_exceeded > time_conflict
    priority_order = ["attendee_unavailable", "daily_limit_exceeded",
                      "time_conflict", "insufficient_duration_slot"]

    # Determine primary reason code
    primary_code = None
    for code in priority_order:
        if code in blocker_set:
            primary_code = code
            break

    # Build combined reason text from ALL blocker types (deduplicated)
    all_texts = []
    for code in priority_order:
        if code in blocker_set:
            for t in sorted(blocker_set[code]):
                all_texts.append(t)

    # Keep it readable: deduplicate, cap to 3 sentences if many
    seen = []
    for t in all_texts:
        if t not in seen:
            seen.append(t)
